#!/usr/sbin/nft -f

flush ruleset

define BLOCKED_IPS = {
    172.66.0.227
}

table ip filter {
    set ip_blocklist {
        type ipv4_addr
        flags interval
        elements = $BLOCKED_IPS
    }

    chain forward {
        type filter hook forward priority filter; policy accept;
        ip daddr @ip_blocklist drop
        ip saddr @ip_blocklist drop
    }
}

table ip nat {
    chain postrouting {
        type nat hook postrouting priority srcnat; policy accept;
        oifname "eth2" masquerade
        oifname "eth0" masquerade
    }
}

